+/// Check if debug logging is enabled (cached)
+fn isDebugEnabled() bool {
+    const State = struct {
+        var checked: bool = false;
+        var enabled: bool = false;
+    };
+    if (!State.checked) {
+        State.enabled = std.posix.getenv("TERMWEB_DEBUG") != null;
+        State.checked = true;
+    }
+    return State.enabled;
+}
